Implementasi Observer Pattern yang robust harus menangani manajemen referensi untuk mencegah memory leaks. Berikut implementasi menggunakan `weakref` dan `threading` untuk keamanan konkurensi dasar.

```python
import weakref
import threading
from abc import ABC, abstractmethod
from typing import List, Any

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject:
    def __init__(self):
        self._observers: List[weakref.ref] = []
        self._lock = threading.Lock()
        self._state: Any = None

    def attach(self, observer: Observer) -> None:
        with self._lock:
            # Gunakan weakref untuk mencegah circular reference memory leaks
            ref = weakref.ref(observer, self._detach_callback)
            if ref not in self._observers:
                self._observers.append(ref)

    def detach(self, observer: Observer) -> None:
        with self._lock:
            for ref in self._observers:
                if ref() is observer:
                    self._observers.remove(ref)
                    break

    def _detach_callback(self, ref: weakref.ref) -> None:
        # Callback otomatis saat observer di-garbage collected
        with self._lock:
            if ref in self._observers:
                self._observers.remove(ref)

    def notify(self) -> None:
        with self._lock:
            # Copy list untuk menghindari RuntimeError saat iterasi jika ada modifikasi
            active_observers = [ref() for ref in self._observers if ref() is not None]

        for observer in active_observers:
            try:
                observer.update(self)
            except Exception as e:
                # Log error tanpa menghentikan notifikasi ke observer lain
                print(f"[ERROR] Observer notification failed: {e}")

    def set_state(self, state: Any) -> None:
        self._state = state
        self.notify()

    def get_state(self) -> Any:
        return self._state

# Contoh Implementasi Concrete Observer
class ConcreteObserver(Observer):
    def __init__(self, name: str):
        self.name = name

    def update(self, subject: Subject) -> None:
        print(f"[{self.name}] Menerima update state: {subject.get_state()}")

# Usage
if __name__ == "__main__":
    subject = Subject()
    obs1 = ConcreteObserver("Observer-1")
    obs2 = ConcreteObserver("Observer-2")

    subject.attach(obs1)
    subject.attach(obs2)

    subject.set_state({"security_level": "HIGH", "timestamp": 1678888888})

    # Cleanup
    subject.detach(obs1)
    subject.set_state({"security_level": "LOW", "timestamp": 1678888899})
```

### Catatan Teknis:
1.  **Memory Management**: Menggunakan `weakref` mencegah observer tetap hidup hanya karena terdaftar di subject. Ini krusial untuk aplikasi long-running.
2.  **Thread Safety**: Menggunakan `threading.Lock` pada operasi attach/detach/notify untuk mencegah race condition.
3.  **Error Handling**: Blok `try-except` pada `notify` memastikan kegagalan satu observer tidak menghentikan notifikasi ke observer lain (fail-safe).
4.  **Security**: Pastikan method `update` tidak mengekspos data sensitif secara tidak sengaja melalui log atau exception message.
